<template>
  <div class="c-event-details">
    <v-container v-if="store.getters['isLoading']">
      <v-card :style="{ minHeight: cardHeight }">
        <v-row>
          <v-col cols="12" class="text-center">
            <div
              class="pa-10"
              style="
                position: absolute;
                top: 50%;
                left: 50%;
                transform: translate(-50%, -50%);
              "
            >
              <v-progress-circular
                indeterminate
                size="128"
                color="#D8B061"
              ></v-progress-circular>
            </div>
          </v-col>
        </v-row>
      </v-card>
    </v-container>
    <v-container v-else>
      <v-card class="px-10">
        <v-row class="mt-10">
          <v-col cols="12">
            <h1 class="text-center">{{ event.event_title }}</h1>
          </v-col>
        </v-row>
        <v-row>
          <v-col cols="12" md="6">
            <v-img
              :src="eventImage"
              alt="Workshop image"
              height="300px"
              @load="onImageLoad"
              contain
            ></v-img>
          </v-col>
          <v-col cols="12" md="6">
            <div class="workshop-details pa-4">
              <v-divider></v-divider>
              <v-list>
                <v-list-item>
                  <v-list-item-title
                    ><strong>Description</strong></v-list-item-title
                  >
                  <v-list-item-content>
                    {{ event.description }}
                  </v-list-item-content>
                </v-list-item>
                <v-list-item>
                  <v-list-item-content>
                    <p class="font-weight-bold">{{ event.details }}</p>
                  </v-list-item-content>
                </v-list-item>
                <v-list-item>
                  <v-list-item-title
                    ><strong>Instructions</strong></v-list-item-title
                  >
                  <v-list-item-content>
                    {{ event.instructions }}
                  </v-list-item-content>
                </v-list-item>
              </v-list>
              <v-divider></v-divider>
            </div>
          </v-col>
        </v-row>

        <v-row>
          <v-cols cols="12">
            <image-slider
              v-if="eventImages.length"
              class="my-8"
              :images="eventImages"
            />
          </v-cols>
        </v-row>
      </v-card>
      <TermListComponent
        v-if="event.category === 'term'"
        :themes="eventThemes"
        :category="event.category"
      />
      <SingleListComponent
        v-if="event.category === 'single'"
        v-model:themes="eventThemes"
        :category="event.category"
        @update:themes="handleThemesUpdate"
      />
    </v-container>
  </div>
</template>

<script lang="ts">
import { defineComponent, ref, onMounted, computed } from "vue";
import TermListComponent from "@/components/TermListComponent.vue";
import SingleListComponent from "@/components/SingleListComponent.vue";
import ImageSlider from "@/components/ImageSlider.vue";
import { useRouter } from "vue-router";
import { useStore } from "vuex";
import { useRoute } from "vue-router";
import { HelperFunctions } from "@/helpers/helpers";
import { Lit } from "@/main";
import { db, doc, getDoc, getDocs, collection, query, where } from "@/main"; // Ensure the correct import of your Firestore instance

interface Event {
  event_title: string;
  start: string; // Update to any to handle Firestore Timestamp
  end: string; // Update to any to handle Firestore Timestamp
  days: any[];
  description: string;
  details: string[];
  instructions: string[];
  price: number;
  term: string;
  category: string;
  quantity: number | null;
  event_id: string;
}

export default defineComponent({
  name: "EventDetailsView",

  components: {
    TermListComponent,
    SingleListComponent,
    ImageSlider,
  },

  setup() {
    const helpers = new HelperFunctions();
    const router = useRouter();
    const route = useRoute();
    const store = useStore();
    const events = ref<any>([]);
    const eventThemes = ref<any>([]);
    const themeId = computed(() => route.params.themeId as string);
    const routeId = ref<string>(router.currentRoute.value.params.id as string);
    const headerHeight = 223; // Adjust this value based on your header's height
    const cardHeight = computed(() => `${window.innerHeight - headerHeight}px`);
    const eventImages = ref<any>([]);

    const env = computed(() =>
      helpers.getEnvironment() === "development" ? "_dev" : ""
    );

    const halfTermPrefixCheck = () => {
      const prefix = (router.currentRoute.value.params.id as string).split(
        "_"
      )[0];
      if (prefix.includes("ht") || prefix.includes("hp")) {
        eventImages.value = [];
      } else {
        eventImages.value = [
          `/img/${routeId.value}/slider-01.jpg`,
          `/img/${routeId.value}/slider-02.jpg`,
          `/img/${routeId.value}/slider-03.jpg`,
          `/img/${routeId.value}/slider-04.jpg`,
          `/img/${routeId.value}/slider-05.jpg`,
          // `/img/${routeId.value}/slider-06.jpg`,
        ];
      }
    };

    const event = ref<Event>({
      event_title: "",
      start: "",
      end: "",
      days: [],
      description: "",
      details: [],
      price: 0,
      instructions: [],
      term: "",
      category: "",
      quantity: null,
      event_id: "",
    });

    const imageLoaded = ref(false);

    const handleThemesUpdate = (updatedThemes: any) => {
      eventThemes.value = updatedThemes;
    };

    const onImageLoad = () => {
      imageLoaded.value = true; // Set image loading state to true when the image loads
      if (!store.getters["isLoading"]) {
        store.dispatch("setLoading", false); // Set loading to false only if data is already loaded
      }
    };

    const termTimes = ref([
      {
        name: "autumn",
        start: "05/09/2024",
        end: "20/12/2024",
        abb: "aw",
      },
      {
        name: "spring",
        start: "08/01/2025",
        end: "27/03/2025",
        abb: "sp",
      },
      {
        name: "summer",
        start: "15/04/2025",
        end: "24/07/2025",
        abb: "su",
      },
    ]);

    const eventImage = computed(() => {
      const themeId = route.params.id as string;
      return `/img/${themeId}/main.jpg`;
    });

    const fetchThemesByEventId = async (eventId: string) => {
      try {
        store.dispatch("setLoading", true); // Set loading to true
        const themesRef = collection(db, `themes${env.value}`); // Reference to the 'themes' collection

        // Extract the suffix (e.g., "fam_sun") from the eventId
        const suffix = eventId.split("_").slice(1).join("_");
        if (!suffix) {
          throw new Error(
            "Invalid eventId format: suffix cannot be determined."
          );
        }

        // Generate all possible prefixes
        const termPrefixes = termTimes.value.flatMap((term) => [
          `${term.abb}01`,
          `${term.abb}02`,
        ]);

        // Initialize the eventThemes structure
        const eventThemesStructure: any = {};
        termPrefixes.forEach((prefix) => {
          eventThemesStructure[prefix] = [];
        });

        // Generate queries for all combinations of prefix and suffix
        const queries = termPrefixes.map((prefix) =>
          query(
            themesRef,
            where("event_id", "==", `${prefix}_${suffix}`) // Match the exact event_id
          )
        );

        // Execute all queries in parallel
        const querySnapshots = await Promise.all(
          queries.map((q) => getDocs(q))
        );

        // Process each query result
        querySnapshots.forEach((querySnapshot, index) => {
          const prefix = termPrefixes[index];

          // Map the documents to theme objects
          const themes = querySnapshot.docs.map((doc) => ({
            ...doc.data(),
            price: event.value.price,
            quantity: 0,
            category: event.value.category,
            purchase_id: Math.random().toString(36).substring(2, 15),
            passed: doc.data().passed,
          }));

          // Filter out passed themes and sort by date
          eventThemesStructure[prefix] = themes
            .filter((theme: any) => !theme.passed)
            .sort(
              (a: any, b: any) =>
                new Date(a.date).getTime() - new Date(b.date).getTime()
            );
        });

        // Update eventThemes with the dynamically structured data
        eventThemes.value = eventThemesStructure;
        store.dispatch("setLoading", false);

        return eventThemesStructure; // Return the structured data
      } catch (error) {
        store.dispatch("setLoading", false);
        console.error("Error fetching themes by event ID:", error);

        // Return a fallback structure with empty arrays
        const fallbackStructure: any = {};
        termTimes.value.forEach((term) => {
          fallbackStructure[`${term.abb}01`] = [];
          fallbackStructure[`${term.abb}02`] = [];
        });
        return fallbackStructure;
      }
    };

    const fetchEvent = async () => {
      const id = router.currentRoute.value.params.id as string;
      const docRef = doc(db, `events${env.value}`, id); // Reference to the specific document
      try {
        store.dispatch("setLoading", true);
        const docSnap = await getDoc(docRef); // Get the document
        if (docSnap.exists()) {
          const eventData = docSnap.data() as Event;
          event.value = eventData;
          Lit.event("event_viewed", {
            metadata: {
              event_title: eventData.event_title,
              event_id: eventData.event_id,
            },
          });
        } else {
          console.error("No such document!");
        }
        store.dispatch("setLoading", false);
      } catch (error) {
        store.dispatch("setLoading", false);
        console.error("Error fetching document:", error);
      }
    };

    onMounted(async () => {
      fetchEvent();
      fetchThemesByEventId(router.currentRoute.value.params.id as string);
      halfTermPrefixCheck();
    });

    return {
      store,
      cardHeight,
      event,
      events,
      eventThemes,
      eventImage,
      themeId,
      routeId,
      eventImages,
      fetchEvent,
      fetchThemesByEventId,
      handleThemesUpdate,
      halfTermPrefixCheck,
      onImageLoad,
    };
  },
});
</script>

